// Normalize incoming payload records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    itemId: String(j.itemId ?? j.id ?? '').trim(),
    source: typeof j.source === 'string' ? j.source.trim() : j.source ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

